import React from 'react';
import { MessageCircle, Phone, LifeBuoy, Laptop } from 'lucide-react';

export default function Ajuda() {
  const contatos = [
    { icon: <MessageCircle size={32} className="text-[#25D366]" />, label: 'WhatsApp', link: 'https://wa.me/5536999154356' },
    { icon: <Phone size={32} />, label: '(46) 3532-2005', link: 'tel:+554635322005' },
    { icon: <Phone size={32} />, label: '(46) 99911-3456', link: 'tel:+5546999113456' },
    { icon: <Phone size={32} />, label: '(46) 99932-5488', link: 'tel:+5546999325488' },
    { icon: <Phone size={32} />, label: '(46) 99932-8037', link: 'tel:+5546999328037' },
    { icon: <Phone size={32} />, label: '(46) 99134-1355', link: 'tel:+5546991341355' },
    { icon: <LifeBuoy size={32} />, label: 'Suporte ao cliente', link: '/suporte' },
    { icon: <Laptop size={32} />, label: 'Acesso Remoto', link: '/acesso-remoto' },
  ];

  return (
    <div className="max-w-4xl mx-auto py-12 px-4">
      <h1 className="text-3xl font-bold text-center mb-2">Entre em contato conosco</h1>
      <p className="text-center text-sm text-gray-600 mb-8">
        Horário de atendimento:<br/>
        Segunda a Sexta: 08:00 às 12:00 e 13:00 às 18:00 &mdash; Sábados (Plantão): 08:00 às 11:30
      </p>

      <div className="grid grid-cols-2 sm:grid-cols-4 gap-6">
        {contatos.map((c, i) => (
          <a
            key={i}
            href={c.link}
            target={c.link.startsWith('http') ? '_blank' : '_self'}
            rel="noopener noreferrer"
            className="flex flex-col items-center justify-center p-6 bg-white rounded-2xl shadow hover:shadow-md transition"
          >
            <div className="mb-3">{c.icon}</div>
            <span className="text-center text-sm font-medium text-gray-800">{c.label}</span>
          </a>
        ))}
      </div>
    </div>
  );
}
